// popover-drag-scroll-snap.js

/**
 * PopoverDragScrollSnap
 * Enables horizontal drag-to-scroll with snap, and vertical drag-to-scroll (with inertia) on figures inside a popover.
 * Handles both mouse and (optionally) touch input.
 */
export default class PopoverDragScrollSnap {
  // Default configuration options
  config = {
    snapSelector: 'figure', // Selector for slides to snap to
    scrollerSelector: '.oversnap-scroller', // Selector for the horizontal scroller
    bodySelector: '.oversnap-body', // Selector for the body containing slides
    prevBtnSelector: '.pop-nav .prev', // Selector for previous button
    nextBtnSelector: '.pop-nav .next', // Selector for next button
    switchThresholdFraction: 1 / 10, // Fraction of slide width to trigger slide switch
    onSlideChange: null, // Callback when slide changes
    onSnapComplete: null, // Callback when snap completes
    verticalDragOnFigures: true, // Enable vertical drag on figures
    verticalDragSpeed: 1, // Multiplier for vertical drag responsiveness
    verticalInertia: true,  // Enable inertia for vertical drag
    inertiaFriction: 0.95,  // Friction for inertia (lower = more inertia)
    inertiaMinVelocity: 0.0, // Minimum velocity to start inertia 0/1
    verticalDraggingClass: 'vertically-dragging', // Class added to figure during drag
    userSelectClass: 'user-select-none', // Not used, but can be used for custom user-select styling
  };

  // Internal state tracking
  state = {
    isDragging: false, // Horizontal drag active
    startX: 0, // Drag start X
    startY: 0, // Drag start Y
    scrollStart: 0, // Scroller scrollLeft at drag start
    activeIndex: 0, // Current slide index
    slideWidth: 1, // Width of current slide
    // For vertical drag
    isVerticallyDragging: false, // Vertical drag active
    figureDragStartY: 0, // Y at vertical drag start
    figureScrollStart: 0, // Figure scrollTop at drag start
    figureDraggingEl: null, // Figure element being vertically dragged
    // For inertia
    lastY: 0, // Last Y position for velocity calculation
    lastTime: 0, // Last timestamp for velocity calculation
    velocityY: 0, // Current vertical velocity
    inertiaFrame: null, // requestAnimationFrame id for inertia
    // For unified drag
    pendingDrag: null, // Pending drag info before direction is determined
  };

  /**
   * Constructor
   * @param {Object} options - Custom configuration
   */
  constructor(options = {}) {
    Object.assign(this.config, options);

    // Find the currently open popover
    this.activePopover = document.querySelector('.project-pop:popover-open');
    // Detect if mouse is supported (pointer: fine)
    this.supportsMouse = window.matchMedia('(pointer: fine)').matches;

    if (!this.activePopover) return;

    this.init();
  }

  /**
   * Initialize DOM references, event listeners, and state
   */
  init() {
    this.scroller = this.activePopover.querySelector(this.config.scrollerSelector);
    this.body = this.scroller?.querySelector(this.config.bodySelector);
    this.slides = Array.from(this.body?.querySelectorAll(this.config.snapSelector) || []);
    this.prevBtn = this.activePopover.querySelector(this.config.prevBtnSelector);
    this.nextBtn = this.activePopover.querySelector(this.config.nextBtnSelector);

    if (this.slides.length <= 1) return;

    // Prevent drag on images/videos to avoid browser drag ghost
    this.body.querySelectorAll('img, video, picture').forEach(el => {
      el.draggable = false;
    });

    // Observe scroller resize to update snapping
    this.resizeObserver = new ResizeObserver(() => {
      requestAnimationFrame(this.onResize);
    });
    this.resizeObserver.observe(this.scroller);

    this.bindEvents();
    this.updateNavState();
  }

  /**
   * Bind all event listeners for drag, scroll, nav, etc.
   */
  bindEvents = () => {
    // Unified drag handler for both horizontal and vertical
    this.scroller?.addEventListener('mousedown', this.onAnyMouseDown, { passive: false });
    document.addEventListener('mouseup', this.onAnyMouseUp);
    document.addEventListener('mousemove', this.onAnyMouseMove);
    this.scroller?.addEventListener('scroll', this.onScroll);

    // Touch support (commented out)
    // this.scroller?.addEventListener('touchend', this.onTouchEnd);

    // Navigation buttons
    this.prevBtn?.addEventListener('click', this.scrollPrev);
    this.nextBtn?.addEventListener('click', this.scrollNext);

    // Keyboard navigation for buttons
    this.prevBtn?.addEventListener('keydown', this.handleKeyNav('prev'));
    this.nextBtn?.addEventListener('keydown', this.handleKeyNav('next'));

    window.addEventListener('resize', this.onResize);

    // Legacy vertical drag logic for configurability
    if (this.config.verticalDragOnFigures) {
      this.body?.addEventListener('mousedown', this.onFigureMouseDown, { passive: false });
    }
    // Clean up vertical drag if mouse leaves figure
    this.slides.forEach(figure => {
      figure.addEventListener('mouseleave', () => {
        // If vertical drag is active on this figure, clean up
        if (this.state.isVerticallyDragging && this.state.figureDraggingEl === figure) {
          this.state.isVerticallyDragging = false;
          figure.classList.remove(this.config.verticalDraggingClass);
          document.body.style.userSelect = '';
          this.state.figureDraggingEl = null;
          this.state.pendingDrag = null;
          // Also cancel inertia if running
          if (this.state.inertiaFrame) {
            cancelAnimationFrame(this.state.inertiaFrame);
            this.state.inertiaFrame = null;
          }
        }
      });
    });
  };

  // --- Unified drag handler for native-feeling scroll ---

  /**
   * Handle mouse down on scroller (start drag, but don't know direction yet)
   */
  onAnyMouseDown = e => {
    if (!this.supportsMouse || e.button !== 0) return;

    // Stop any running inertia and remove drag class
    if (this.state.inertiaFrame) {
      cancelAnimationFrame(this.state.inertiaFrame);
      this.state.inertiaFrame = null;
    }
    if (this.state.figureDraggingEl) {
      this.state.figureDraggingEl.classList.remove(this.config.verticalDraggingClass);
    }

    // Store initial state for both drag types
    this.state.pendingDrag = {
      startX: e.clientX,
      startY: e.clientY,
      target: e.target,
      figure: e.target.closest(this.config.snapSelector),
      imgOrPic: e.target.closest('img, picture')
    };
    this.state.isDragging = false;
    this.state.isVerticallyDragging = false;

    // Debug
    // console.log('Any drag start', this.state.pendingDrag.figure);
  };

  /**
   * Handle mouse move: decide drag direction, and perform drag
   */
  onAnyMouseMove = e => {
    const pending = this.state.pendingDrag;
    if (!pending) return;

    const dx = e.clientX - pending.startX;
    const dy = e.clientY - pending.startY;
    const threshold = 6; // px before locking in direction

    // Not yet dragging: decide direction
    if (!this.state.isDragging && !this.state.isVerticallyDragging) {
      if (Math.abs(dx) < threshold && Math.abs(dy) < threshold) return;

      // Vertical drag if mostly vertical and on img/pic in figure
      if (
        Math.abs(dy) > Math.abs(dx) &&
        Math.abs(dy) > threshold &&
        pending.imgOrPic &&
        pending.figure
      ) {
        // Start vertical drag
        this.state.isVerticallyDragging = true;
        this.state.figureDragStartY = pending.startY;
        this.state.figureScrollStart = pending.figure.scrollTop;
        this.state.figureDraggingEl = pending.figure;
        this.state.lastY = pending.startY;
        this.state.lastTime = performance.now();
        this.state.velocityY = 0;
        pending.figure.classList.add(this.config.verticalDraggingClass);
        document.body.style.userSelect = 'none';
        return;
      }

      // Horizontal drag if mostly horizontal
      if (
        Math.abs(dx) > Math.abs(dy) &&
        Math.abs(dx) > threshold
      ) {
        this.state.isDragging = true;
        this.state.startX = pending.startX;
        this.state.startY = pending.startY;
        this.state.scrollStart = this.scroller.scrollLeft;
        this.state.slideWidth = this.slides[this.state.activeIndex]?.offsetWidth || 1;
        this.scroller.classList.add('dragging');
        this.scroller.style.scrollSnapType = 'none';
        this.body.style.pointerEvents = 'none';
        document.body.style.userSelect = 'none';
        return;
      }
    }

    // Handle vertical drag
    if (this.state.isVerticallyDragging) {
      e.preventDefault();
      const speed = this.config.verticalDragSpeed || 1.7;
      const now = performance.now();
      const dy = (e.clientY - this.state.figureDragStartY) * speed;
      this.state.figureDraggingEl.scrollTop = this.state.figureScrollStart - dy;

      // Calculate velocity for inertia
      const dt = now - this.state.lastTime;
      if (dt > 0) {
        this.state.velocityY = ((e.clientY - this.state.lastY) / dt) * speed;
      }
      this.state.lastY = e.clientY;
      this.state.lastTime = now;
      return;
    }

    // Handle horizontal drag
    if (this.state.isDragging) {
      e.preventDefault();
      const dx = e.clientX - this.state.startX;
      this.scroller.scrollLeft = this.state.scrollStart - dx;
      return;
    }
  };

  /**
   * Handle mouse up: finish drag, snap, and possibly apply inertia
   */
  onAnyMouseUp = e => {
    // End vertical drag
    if (this.state.isVerticallyDragging) {
      this.state.isVerticallyDragging = false;
      if (this.state.figureDraggingEl) {
        this.state.figureDraggingEl.classList.remove(this.config.verticalDraggingClass);
      }
      document.body.style.userSelect = '';

      // Debug
      // console.log('Vertical drag end', this.state.figureDraggingEl);

      // Inertia for vertical drag
      if (
        this.config.verticalInertia &&
        this.state.figureDraggingEl &&
        Math.abs(this.state.velocityY) > this.config.inertiaMinVelocity
      ) {
        this.applyVerticalInertia(
          this.state.figureDraggingEl,
          this.state.velocityY * 10 // scale for px/sec
        );
      }

      this.state.figureDraggingEl = null;
      this.state.pendingDrag = null;
      return;
    }

    // End horizontal drag
    if (this.state.isDragging) {
      this.endDrag();

      const dx = e.clientX - this.state.startX;
      const threshold = this.state.slideWidth * (this.config.switchThresholdFraction || 1 / 8);

      let newIndex = this.state.activeIndex;
      if (dx > threshold && newIndex > 0) newIndex--;
      else if (dx < -threshold && newIndex < this.slides.length - 1) newIndex++;

      this.scrollToIndex(newIndex);
    }

    this.state.isDragging = false;
    this.state.pendingDrag = null;
  };

  // --- Legacy vertical drag-to-scroll on figures (mouse only) ---

  /**
   * Handle mouse down on a figure for legacy vertical drag
   */
  onFigureMouseDown = e => {
    if (!this.supportsMouse || e.button !== 0) return;

    // Stop any running inertia and remove drag class
    if (this.state.inertiaFrame) {
      cancelAnimationFrame(this.state.inertiaFrame);
      this.state.inertiaFrame = null;
    }
    if (this.state.figureDraggingEl) {
      this.state.figureDraggingEl.classList.remove(this.config.verticalDraggingClass);
    }

    const imgOrPic = e.target.closest('img, picture');
    if (!imgOrPic) return;
    const figure = e.target.closest(this.config.snapSelector);
    if (!figure) return;
    // Prevent horizontal drag from starting
    this.state.isVerticallyDragging = true;
    this.state.figureDragStartY = e.clientY;
    this.state.figureScrollStart = figure.scrollTop;
    this.state.figureDraggingEl = figure;
    this.state.lastY = e.clientY;
    this.state.lastTime = performance.now();
    this.state.velocityY = 0;

    figure.classList.add(this.config.verticalDraggingClass);
    document.body.style.userSelect = 'none';

    // Attach listeners for move/up
    document.addEventListener('mousemove', this.onFigureMouseMove, { passive: false });
    document.addEventListener('mouseup', this.onFigureMouseUp);
  };

  /**
   * Handle mouse move for legacy vertical drag
   */
  onFigureMouseMove = e => {
    if (!this.state.isVerticallyDragging) return;

    e.preventDefault();
    const speed = this.config.verticalDragSpeed || 1.7;
    const now = performance.now();
    const dy = (e.clientY - this.state.figureDragStartY) * speed;
    this.state.figureDraggingEl.scrollTop = this.state.figureScrollStart - dy;

    // Calculate velocity for inertia
    const dt = now - this.state.lastTime;
    if (dt > 0) {
      this.state.velocityY = ((e.clientY - this.state.lastY) / dt) * speed;
    }
    this.state.lastY = e.clientY;
    this.state.lastTime = now;
  };

  /**
   * Handle mouse up for legacy vertical drag
   */
  onFigureMouseUp = () => {
    if (!this.state.isVerticallyDragging) return;
    this.state.isVerticallyDragging = false;
    if (this.state.figureDraggingEl) {
      this.state.figureDraggingEl.classList.remove(this.config.verticalDraggingClass);
    }
    document.body.style.userSelect = '';

    // Inertia for vertical drag
    if (
      this.config.verticalInertia &&
      this.state.figureDraggingEl &&
      Math.abs(this.state.velocityY) > this.config.inertiaMinVelocity
    ) {
      this.applyVerticalInertia(
        this.state.figureDraggingEl,
        this.state.velocityY * 100 // scale for px/sec
      );
    }

    document.removeEventListener('mousemove', this.onFigureMouseMove);
    document.removeEventListener('mouseup', this.onFigureMouseUp);
    this.state.figureDraggingEl = null;
  };

  /**
   * Apply inertia effect to vertical drag after mouse up
   * @param {HTMLElement} el - The figure element
   * @param {number} initialVelocity - Initial velocity in px/sec
   */
  applyVerticalInertia = (el, initialVelocity) => {
    let velocity = initialVelocity;
    let lastScroll = el.scrollTop;
    const friction = this.config.inertiaFriction || 0.92;
    const minVelocity = this.config.inertiaMinVelocity || 0.1;

    el.classList.add(this.config.verticalDraggingClass);

    const step = () => {
      if (Math.abs(velocity) > minVelocity) {
        el.scrollTop -= velocity;
        if (el.scrollTop === lastScroll) {
          el.classList.remove(this.config.verticalDraggingClass);
          this.state.inertiaFrame = null;
          return;
        }
        lastScroll = el.scrollTop;
        velocity *= friction;
        this.state.inertiaFrame = requestAnimationFrame(step);
      } else {
        el.classList.remove(this.config.verticalDraggingClass);
        this.state.inertiaFrame = null;
      }
    };
    step();
  };

  // --- Prevent horizontal drag if vertical drag is active ---

  /**
   * (Legacy) Handle mouse down for horizontal drag
   */
  onMouseDown = e => {
    if (this.state.isVerticallyDragging) return; // Don't start horizontal drag if vertical drag is active
    if (!this.supportsMouse || e.button !== 0) return;

    const { clientX, clientY } = e;

    Object.assign(this.state, {
      isDragging: true,
      startX: clientX,
      startY: clientY,
      scrollStart: this.scroller.scrollLeft,
      slideWidth: this.slides[this.state.activeIndex]?.offsetWidth || 1,
    });

    this.scroller.classList.add('dragging');
    this.scroller.style.scrollSnapType = 'none';
    this.body.style.pointerEvents = 'none';
    document.body.style.userSelect = 'none';
  };

  /**
   * (Legacy) Handle mouse move for horizontal drag
   */
  onMouseMove = e => {
    if (this.state.isVerticallyDragging) return; // Don't run horizontal drag if vertical drag is active
    if (!this.state.isDragging) return;

    const dx = e.clientX - this.state.startX;
    const dy = e.clientY - this.state.startY;

    if (Math.abs(dy) > Math.abs(dx) && Math.abs(dy) > 10) {
      this.endDrag();
      return;
    }

    e.preventDefault();
    this.scroller.scrollLeft = this.state.scrollStart - dx;
  };

  /**
   * (Legacy) Handle mouse up for horizontal drag
   */
  onMouseUp = e => {
    if (this.state.isVerticallyDragging) return; // Don't run horizontal drag if vertical drag is active
    if (!this.state.isDragging) return;

    this.endDrag();

    const dx = e.clientX - this.state.startX;
    const threshold = this.state.slideWidth * (this.config.switchThresholdFraction || 1 / 8);

    let newIndex = this.state.activeIndex;
    if (dx > threshold && newIndex > 0) newIndex--;
    else if (dx < -threshold && newIndex < this.slides.length - 1) newIndex++;

    this.scrollToIndex(newIndex);
  };

  /**
   * End drag: clean up classes and styles
   */
  endDrag = () => {
    this.state.isDragging = false;
    this.scroller.classList.remove('dragging');
    this.scroller.style.scrollSnapType = '';
    this.body.style.pointerEvents = '';
    document.body.style.userSelect = '';
  };

  /**
   * Handle scroll event: update nav state, snap, and fire callbacks
   */
  onScroll = () => {
    // Always update activeIndex and nav state, but only snap for mouse devices
    const closestIndex = this.getClosestIndex();
    if (this.state.activeIndex !== closestIndex) {
      this.state.activeIndex = closestIndex;
      this.updateNavState();
      this.config.onSlideChange?.(closestIndex);
    }

    // Only snap for mouse devices (pointer: fine)
    if (this.supportsMouse) {
      clearTimeout(this._scrollTimeout);
      this._scrollTimeout = setTimeout(this.snapToNearest, 80);
    }
  };

  /**
   * Handle window resize: snap to nearest slide
   */
  onResize = () => {
    this.snapToNearest();
  };

  /**
   * Utility: Find the closest slide index to the current scroll position
   * @returns {number} Closest slide index
   */
  getClosestIndex = () => {
    const scrollLeft = this.scroller.scrollLeft;
    const snapPoints = this.slides.map(slide => slide.offsetLeft);
    return snapPoints.reduce((closest, current, index) =>
      Math.abs(current - scrollLeft) < Math.abs(snapPoints[closest] - scrollLeft)
        ? index
        : closest,
      0
    );
  };

  /**
   * Snap to the nearest slide
   */
  snapToNearest = () => {
    // Only run snapping logic for mouse devices
    // if (!this.supportsMouse) return;
    const closestIndex = this.getClosestIndex();
    this.state.activeIndex = closestIndex;
    this.updateNavState();
    this.scrollToIndex(closestIndex);
    this.config.onSnapComplete?.(closestIndex);
  };

  /**
   * Scroll to a specific slide index
   * @param {number} index - Slide index to scroll to
   */
  scrollToIndex = index => {
    const target = this.slides[index]?.offsetLeft;
    if (target == null) return;

    this.scroller.scrollTo({ left: target /*, behavior: 'smooth' */ });
    this.state.activeIndex = index;
    this.updateNavState();
    this.config.onSlideChange?.(index);
    // Debug
    // console.log('Scrolled to index:', index, 'at position:', target);
  };

  /**
   * Scroll to previous slide
   */
  scrollPrev = () => {
    this.scrollToIndex(Math.max(0, this.state.activeIndex - 1));
  };

  /**
   * Scroll to next slide
   */
  scrollNext = () => {
    this.scrollToIndex(Math.min(this.slides.length - 1, this.state.activeIndex + 1));
  };

  /**
   * Update navigation button state (enable/disable)
   */
  updateNavState = () => {
    const { activeIndex } = this.state;
    const maxIndex = this.slides.length - 1;

    if (this.prevBtn) this.prevBtn.disabled = activeIndex <= 0;
    if (this.nextBtn) this.nextBtn.disabled = activeIndex >= maxIndex;
  };

  /**
   * Handle keyboard navigation for nav buttons
   * @param {'prev'|'next'} direction
   */
  handleKeyNav = direction => e => {
    if (e.key === 'Enter' || e.key === ' ' || e.key === 'Spacebar') {
      e.preventDefault();
      if (direction === 'prev') this.scrollPrev();
      if (direction === 'next') this.scrollNext();
    }
  };

  /**
   * Clean up all event listeners and observers
   */
  destroy = () => {
    // Unified drag
    this.scroller?.removeEventListener('mousedown', this.onAnyMouseDown);
    document.removeEventListener('mouseup', this.onAnyMouseUp);
    document.removeEventListener('mousemove', this.onAnyMouseMove);

    // Legacy drag
    this.scroller?.removeEventListener('mousedown', this.onMouseDown);
    document.removeEventListener('mouseup', this.onMouseUp);
    document.removeEventListener('mousemove', this.onMouseMove);

    this.scroller?.removeEventListener('scroll', this.onScroll);
    window.removeEventListener('resize', this.onResize);

    this.prevBtn?.removeEventListener('click', this.scrollPrev);
    this.nextBtn?.removeEventListener('click', this.scrollNext);

    if (this.config.verticalDragOnFigures) {
      this.body?.removeEventListener('mousedown', this.onFigureMouseDown);
      document.removeEventListener('mousemove', this.onFigureMouseMove);
      document.removeEventListener('mouseup', this.onFigureMouseUp);
    }

    if (this.state.inertiaFrame) {
      cancelAnimationFrame(this.state.inertiaFrame);
      this.state.inertiaFrame = null;
    }
    // Remove dragging class from any figure
    if (this.state.figureDraggingEl) {
      this.state.figureDraggingEl.classList.remove(this.config.verticalDraggingClass);
    }

    this.resizeObserver?.disconnect();
  };
}